import{_ as a,o as e,c as i,a2 as l}from"./chunks/framework.DIMps2S2.js";const m=JSON.parse('{"title":"ATM 与柜台入金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/hk-methods/atm-and-counter.md","filePath":"zh-CN/deposit/hk-methods/atm-and-counter.md"}'),o={name:"deposit/hk-methods/atm-and-counter.md"};function r(d,t,h,n,s,u){return e(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="atm-与柜台入金" tabindex="-1">ATM 与柜台入金 <a class="header-anchor" href="#atm-与柜台入金" aria-label="Permalink to &quot;ATM 与柜台入金&quot;">​</a></h1><p>通过香港银行 ATM 或银行柜台将资金转账至长桥收款账户，转账完成后需上传汇款凭证。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>港元（HKD）、美元（USD）</td></tr><tr><td>预计到账时间</td><td>同行转账：2 小时内；跨行转账：1–3 个工作日</td></tr><tr><td>手续费</td><td>长桥免费，具体费用以银行实际收取为准</td></tr></tbody></table><h2 id="收款银行信息" tabindex="-1">收款银行信息 <a class="header-anchor" href="#收款银行信息" aria-label="Permalink to &quot;收款银行信息&quot;">​</a></h2><ul><li>收款人名称：Long Bridge HK Limited</li><li>港元收款账号：01287520564946</li><li>美元收款账号：01287520564962</li><li>收款银行：中国银行（香港）有限公司（银行编号：012）</li><li>SWIFT 代码：BKCHHKHHXXX</li><li>银行地址：2A Des Voeux Road Central, Hong Kong</li></ul><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li>获取长桥收款账户信息（见上方）</li><li>前往香港银行 ATM 或柜台，将资金转账至长桥收款账户</li><li>保留汇款凭证截图（ATM 打印凭条或柜台回执）</li><li>打开长桥 App，进入<strong>资产 → 存入资金 → 选择币种 → ATM / 柜台转账</strong>，上传汇款凭证</li></ol><blockquote><p>完成转账后请立即上传凭证，否则影响入金进度。</p></blockquote><h2 id="同名账户要求与使用限制" tabindex="-1">同名账户要求与使用限制 <a class="header-anchor" href="#同名账户要求与使用限制" aria-label="Permalink to &quot;同名账户要求与使用限制&quot;">​</a></h2><ul><li>仅适用于香港银行柜台及 ATM</li><li>转账银行账户名必须与证券账户名同名，不可使用他人账户</li><li>香港公众假期不处理汇款业务，请预留时间</li><li>不接受直接存入现金</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit/methods-overview">入金方式总览</a> — 对比所有入金方式的预计到账时间与手续费</li><li><a href="/wiki/troubleshooting/deposit-not-received">入金未到账排查</a> — 超出预期时间未到账时的排查步骤</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit">入金</a></li><li><a href="/wiki/deposit/methods-overview">入金方式</a></li></ul>',15)])])}const p=a(o,[["render",r]]);export{m as __pageData,p as default};
